#include<bits/stdc++.h>
#define LL long long
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e5+5;
struct node{LL id,num;}a[N];
LL n,Q,s[N],p[N],Sum;
bool cmp(node d1,node d2){return d1.num<d2.num;}
LL FLS(LL x){//Find Last Small
    LL l=1,r=n,as=0;
    while(l<=r){
        int mid=(l+r)/2;
        if(a[mid].num<=x)as=mid,l=mid+1;
        else r=mid-1;
    }
    return as;
}
int main(){
    //freopen("msum.in","r",stdin);
    //freopen("msum.out","w",stdout);
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i].num,a[i].id=i;
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)p[a[i].id]=i;
    for(int i=1;i<=n;i++)s[i]=s[i-1]+a[i].num;
    for(int i=1;i<=n;i++)Sum+=a[i].num*(1ll*i);
    cin>>Q;
    while(Q--){
        LL x,y;cin>>x>>y;
        if(y>a[p[x]].num){//变大
            LL D=FLS(y);
            LL ans=Sum;
            ans-=s[D]-s[p[x]];
            ans-=p[x]*a[p[x]].num;
            ans+=D*y;
            cout<<ans<<"\n";
        }
        else if(y==a[p[x]].num)cout<<Sum<<"\n";
        else{//变小
            LL D=FLS(y);
            LL ans=Sum;
            ans+=s[p[x]-1]-s[D];
            ans-=p[x]*a[p[x]].num;
            ans+=(D+1)*y;
            cout<<ans<<"\n";
        }
    }
    return 0;
}
/*


分两种情况——变大 & 变小

首先考虑变大的情况

1 3 4 7 19

如将 3 改为 10，原序列会变为：

1 4 7 10 19

也就是说，原序列中 [3,4] 这个区间的数的贡献各少了一个

那么我们要二分找到这个位置

并且我们的 3 的原贡献可以删去

加上新贡献，有 4 次，即二分找到的那个位置

变小的情况同理，二分去找，那个区间的贡献各多了一个

然后也要减去原贡献并加上新贡献

那么维护好前缀和即可


*/
